from google_adk.tools import ToolCall

def batch_analyzer(tools: list[ToolCall]):
    sequential_calls = []
    for i, tool in enumerate(tools):
        if tool.execution_time > 1.0 and not tool.batched:
            sequential_calls.append({
                'tool': tool.name,
                'latency': tool.execution_time,
                'parallelizable': tool.can_parallelize
            })

    if len(sequential_calls) > 2:
        total_latency = sum(t['latency'] for t in sequential_calls)
        print(f'🚨 UNBATCHED TOOLS: {len(sequential_calls)} calls = {total_latency:.1f}s wasted')

    return tools

# Register before tool execution
agent.tool_pipeline = batch_analyzer

