from google_adk import Agent
from typing import Dict, Set

class CycleBreaker:
    def __init__(self):
        self.active_chains: Dict[str, Set[str]] = {}

    def check_delegation(self, chain: list[str], ttl: int = 3) -> bool:
        agent_id = chain[-1]
        chain_key = '_'.join(chain[-ttl:])

        if chain_key in self.active_chains.get(agent_id, set()):
            print(f'🚫 CIRCUIT BREAK: Loop detected in {chain[-ttl:]}')
            return False

        self.active_chains.setdefault(agent_id, set()).add(chain_key)
        return True

cycle_breaker = CycleBreaker()
agent.before_delegate = lambda chain: cycle_breaker.check_delegation(chain)

from google_adk import SessionState

def sticky_model_policy(session: SessionState):
    if not session.get('locked_model'):
        session['locked_model'] = session.config.model
        print(f'🔒 Model locked to {session["locked_model"]} for session')
    else:
        session.config.model = session['locked_model']

# Apply at session init
session.on_init(sticky_model_policy)
agent.session_policies.append(sticky_model_policy)
